void main() {
  TestWidgetsFlutterBinding.ensureInitialized();

  const methodChannel = MethodChannel(
    'com.trebuchetdynamics.navivox/connect_intents',
  );

  tearDown(() {
    TestDefaultBinaryMessengerBinding.instance.defaultBinaryMessenger
        .setMockMethodCallHandler(methodChannel, null);
  });

  test(
    'initialImport replays payload consumed by availability probe',
    () async {
      var calls = 0;
      final payload = {
        'payload': 'https://gateway.example/connect?token=nvbx_token',
        'source': 'shared_text',
      };
      TestDefaultBinaryMessengerBinding.instance.defaultBinaryMessenger
          .setMockMethodCallHandler(methodChannel, (call) async {
            expect(call.method, 'initialConnectIntent');
            calls += 1;
            return calls == 1 ? payload : null;
          });

      final observer = NavivoxConnectIntentObserver();
      final source = NavivoxConnectIntentSource(
        methodChannel: methodChannel,
        observer: observer,
      );

      expect(await source.isAvailable(), isTrue);

      final result = await source.initialImport();

      expect(calls, 1);
      expect(result, isNotNull);
      expect(result!.baseUrl, 'https://gateway.example');
      expect(result.token, 'nvbx_token');
      expect(result.source, PairingHandoffSource.sharedText);
      expect(identical(observer.lastImport, result), isTrue);
    },
  );

  test(
    'repeated availability checks do not drop cached initial payload',
    () async {
      var calls = 0;
      final payload = {
        'payload': 'https://gateway.example/connect?token=nvbx_token',
        'source': 'direct_app_open',
      };
      TestDefaultBinaryMessengerBinding.instance.defaultBinaryMessenger
          .setMockMethodCallHandler(methodChannel, (call) async {
            expect(call.method, 'initialConnectIntent');
            calls += 1;
            return calls == 1 ? payload : null;
          });

      final source = NavivoxConnectIntentSource(methodChannel: methodChannel);

      expect(await source.isAvailable(), isTrue);
      expect(await source.isAvailable(), isTrue);

      final result = await source.initialImport();

      expect(calls, 2);
      expect(result, isNotNull);
      expect(result!.baseUrl, 'https://gateway.example');
      expect(result.token, 'nvbx_token');
      expect(result.source, PairingHandoffSource.directAppOpen);
    },
  );
}

class NavivoxInitialConnectIntentPayloadCache {
  Object? _payload;
  bool _hasPayload = false;

  bool get hasPayload => _hasPayload;

  /// Caches the first platform payload observed before [take].
  ///
  /// Android initial intents are one-shot: repeated availability probes can
  /// return `null` after the first probe consumes the real payload. Treat the
  /// cache as a replay buffer and keep the earliest unconsumed result.
  void remember(Object? payload) {
    if (_hasPayload) return;
    _payload = payload;
    _hasPayload = true;
  }

  Object? take() {
    final payload = _payload;
    _payload = null;
    _hasPayload = false;
    return payload;
  }
}

import 'navivox_connect_intent_initial_payload.dart';

void main() {
  preservesPayloadObservedDuringAvailabilityProbe();
  remembersNullAvailabilityProbePayload();
  keepsFirstUnconsumedProbePayloadAcrossRepeatedAvailabilityChecks();
}

void preservesPayloadObservedDuringAvailabilityProbe() {
  final cache = NavivoxInitialConnectIntentPayloadCache();
  final payload = {
    'payload': 'https://gateway.example/connect?token=nvbx_token',
    'source': 'shared_text',
  };

  cache.remember(payload);

  _expect(
    cache.hasPayload,
    'availability probe payload should be marked cached',
  );
  _expect(
    identical(cache.take(), payload),
    'initial import should consume the payload returned by the availability probe',
  );
  _expect(
    !cache.hasPayload,
    'availability probe payload should be consumed only once',
  );
}

void remembersNullAvailabilityProbePayload() {
  final cache = NavivoxInitialConnectIntentPayloadCache();

  cache.remember(null);

  _expect(
    cache.hasPayload,
    'null availability probe result should still be treated as a completed probe',
  );
  _expect(
    cache.take() == null,
    'null availability probe result should be replayable without a second probe',
  );
  _expect(!cache.hasPayload, 'null probe result should be consumed only once');
}

void keepsFirstUnconsumedProbePayloadAcrossRepeatedAvailabilityChecks() {
  final cache = NavivoxInitialConnectIntentPayloadCache();
  final firstPayload = {
    'payload': 'https://gateway.example/connect?token=nvbx_token',
    'source': 'direct_app_open',
  };

  cache.remember(firstPayload);
  cache.remember(null);

  _expect(
    identical(cache.take(), firstPayload),
    'repeated availability probes should not overwrite the first cached initial intent',
  );
}

