      candidate: candidate,
      tokenSearchStart: endpoint.tokenSearchStart,
      tokenSearchEnd: endpoint.tokenSearchEnd,
      hasFollowingToken:
          _firstToken(
            text,
            start: endpoint.tokenSearchStart,
            end: endpoint.tokenSearchEnd,
          ) !=
          null,
    );
    bestCandidate = sharedTextCandidate.isRicherThan(bestCandidate)
        ? sharedTextCandidate
        : bestCandidate;
  }
